#======================================STRUCTURE(POLYGON)======================================================

	LAYER
		NAME 'STRP'
		TYPE POLYGON
		DUMP true
		TEMPLATE fooOnlyForWMSGetFeatureInfo		
		INCLUDE "datashare.inc"
		DATA 'sp_geometry FROM vw_att_details_structure_map  USING UNIQUE system_id USING srid=4326'	
		FILTER (%provinceFilter% AND (%layerFilter% ) )
		
		VALIDATION		
			'provinceFilter'   '.*'	
            'layerFilter'   '.*'	
