	# ================================== CABLE ======================================== 
	LAYER
		NAME 'CBL'
		TYPE LINE
		DUMP true
		TEMPLATE fooOnlyForWMSGetFeatureInfo
		#EXTENT 72.504366 18.900959 73.403214 19.320367
		INCLUDE "datashare.inc"		
		DATA 'sp_geometry FROM vw_att_details_cable_map USING UNIQUE system_id USING srid=4326'	
		FILTER (%provinceFilter% AND (%layerFilter% ) AND (%prjectspecificationFilter% ) AND (%cableFilter%) AND (%ownershipFilter%) AND (%PODFilter%) and (%NetworkFilter%)AND (%AutoPlanningNetworkFilter%) )		

		VALIDATION		
			'provinceFilter'   '.*'
			'layerFilter'   '.*'
			'prjectspecificationFilter'   '.*'	
            'cableFilter'   '.*'
			'ownershipFilter'   '.*'				
			'PODFilter'   '.*'
			'NetworkFilter' '.*'
			'AutoPlanningNetworkFilter' '.*'
		END 
		METADATA
			'ows_title' 'CABLE'
		END
		STATUS OFF
		GROUP 'Network'
		TRANSPARENCY 100
		LABELITEM 'label_column'
		PROJECTION
			'proj=longlat'
			'datum=WGS84'
			'no_defs'
		END
		
		CLASSITEM 'cable_cores' 		 
		#====================Planned======================
		CLASS 
			EXPRESSION ('[network_status]'  eq 'P')					
		     STYLE
				WIDTH 2
				COLOR [color_code]				                					
				PATTERN 10 5  END
			END	
			LABEL
			    OUTLINEWIDTH 5
				OUTLINECOLOR 255 255 255
				COLOR 0 0 0	
				FONT arial
				TYPE truetype							
				SIZE 8
				STYLE
					GEOMTRANSFORM 'labelpoly'
					COLOR [color_code]  # background rect.
				END
				OFFSET 0 0
				ANTIALIAS TRUE
				POSITION CC
				ANGLE AUTO
				FORCE FALSE
				PARTIALS FALSE
				MAXSCALEDENOM 70000
			END
		END	
		#====================Dormant======================		
		CLASS 
			EXPRESSION ('[network_status]'  eq 'D')						
		     STYLE
				WIDTH 2
				COLOR [color_code]				                					
				PATTERN 10 5 0 5  END
			END	
			LABEL
			    OUTLINEWIDTH 5
				OUTLINECOLOR 255 255 255
				COLOR 0 0 0	
				FONT arial
				TYPE truetype								
				SIZE 8
				STYLE
					GEOMTRANSFORM 'labelpoly'
					COLOR [color_code]  # background rect.
				END				
				OFFSET 0 0
				ANTIALIAS TRUE
				POSITION CC
				ANGLE AUTO
				FORCE FALSE
				PARTIALS FALSE
				MAXSCALEDENOM 70000
			END
		END	
		#====================As-Built======================
		CLASS 
			EXPRESSION ('[network_status]'  eq 'A')						
		     STYLE
				WIDTH 2
				COLOR [color_code]				                						
			END	
			LABEL
			    OUTLINEWIDTH 5
				OUTLINECOLOR 255 255 255
				COLOR 0 0 0	
				FONT arial
				TYPE truetype				
				SIZE 8
				STYLE
					GEOMTRANSFORM 'labelpoly'
					COLOR [color_code]  # background rect.
				END
				OFFSET 0 0
				ANTIALIAS TRUE
				POSITION CC
				ANGLE AUTO
				FORCE FALSE
				PARTIALS FALSE
				MAXSCALEDENOM 70000
			END
		END		
	END
