		#====================Planned======================
		CLASS 
			NAME "count_ducts"
			#TEXT "[count_ducts]"
			#EXPRESSION "count_ducts"
			EXPRESSION ('[network_status]'  eq 'P')	
			STYLE
				WIDTH 3
				COLOR 255 0 0
				LINECAP ROUND
				PATTERN 10 10 END
			END
			LABEL
			    OUTLINEWIDTH 5
				OUTLINECOLOR 255 255 255
				FONT arial
				TYPE truetype
				COLOR 0 0 0
				#COLOR  255 0 0
				SIZE 8
