				END
				STYLE
					GEOMTRANSFORM 'labelunderline'
					COLOR   0 0 255 # underline
					OFFSET 	0 -1 	# with some offset
				END
				OFFSET 0 0
				ANTIALIAS TRUE
				POSITION CC
				ANGLE AUTO
				FORCE FALSE
				PARTIALS FALSE
			END
		END
		
			#====================As-Built======================
