        SIZE 8
        STYLE
            GEOMTRANSFORM 'labelpoly'
            COLOR 255 0 0  # red background rectangle
        END
        STYLE
            GEOMTRANSFORM 'labelunderline'
            COLOR 0 0 255  # optional: blue underline
            OFFSET 0 -1
        END
        OFFSET 0 0
        ANTIALIAS TRUE
        POSITION CC
        ANGLE AUTO
        FORCE FALSE
        PARTIALS FALSE
    END
END

