	# ===================ROW======================================= 	
	LAYER 
		NAME 'ROW'		
		TYPE POLYGON
		DUMP true
		TEMPLATE fooOnlyForWMSGetFeatureInfo
		INCLUDE "datashare.inc"
		#PROCESSING "NATIVE_FILTER=%provinceFilter%"
		DATA 'sp_geometry FROM "vw_att_details_row_map" USING UNIQUE system_id USING srid=4326'
		FILTER  ((%provinceFilter%)  AND (%prjectspecificationFilter% )  and (%NetworkFilter%))
		
		VALIDATION		
			'provinceFilter'   '.*'	
			'prjectspecificationFilter'   '.*'
			'NetworkFilter'   '.*'
		END 
		METADATA
			'ows_title' 'ROW'
		END
		STATUS OFF
		GROUP 'Network'
		TRANSPARENCY 30
		PROJECTION
			'proj=longlat'  
			'datum=WGS84'
			'no_defs'
		END			
		
		CLASS
			NAME 'ROW' 
			TEXT "[row_text]"	
			STYLE
				WIDTH 1
				OUTLINECOLOR 0 0 0
				COLOR [color_code] 
			END
			LABEL
			    OUTLINEWIDTH 5
				OUTLINECOLOR 255 255 255
				FONT arial
				TYPE truetype
				COLOR 0 0 0				
				SIZE 8								
				OFFSET 0 0
				ANTIALIAS TRUE
				POSITION CC
				ANGLE AUTO
				FORCE FALSE
				PARTIALS FALSE				
			END		
		END
	END
	
