	# ================================== ROW Center Line ======================================== 
	LAYER
		NAME 'ROWL'
		TYPE LINE
		DUMP true
		TEMPLATE fooOnlyForWMSGetFeatureInfo
		#EXTENT 72.504366 18.900959 73.403214 19.320367
		INCLUDE "datashare.inc"		
		DATA 'center_line_geom FROM vw_att_details_row_map USING UNIQUE system_id USING srid=4326'	
		FILTER  (%provinceFilter% AND (%prjectspecificationFilter% ))
		
		VALIDATION		
			'provinceFilter'   '.*'	
